#include <stdio.h>
#define DIM 5

int main() {
    int i, j, broj_indeksa, red1, red2, temp;
    int matrica[DIM][DIM] = {
        {1, 2, 3, 4, 5},
        {6, 7, 8, 9, 9},
        {8, 7, 6, 5, 4},
        {3, 2, 1, 1, 2},
        {3, 4, 5, 6, 7}
    };
    
    printf("Koliko indeksa zelite unijeti (mora biti paran broj >= 2)? ");
    scanf("%d", &broj_indeksa);
    
    if (broj_indeksa < 2 || broj_indeksa % 2 != 0) {
        printf("Broj indeksa mora biti paran broj >= 2!");
        return 1;
    }

    printf("Unesite indekse redova koje zelite zamijeniti (0-%d): \n", DIM - 1);
    for (i = 0; i < broj_indeksa; i += 2) {
        scanf("%d %d", &red1, &red2);
    
        if (red1 < 0 || red1 >= DIM || red2 < 0 || red2 >= DIM || red1 == red2) {
            printf("Nevalidan unos!");
            return 1;
        }

        /* Zamjena redova */
        for (j = 0; j < DIM; j++) {
            temp = matrica[red1][j];
            matrica[red1][j] = matrica[red2][j];
            matrica[red2][j] = temp;
        }
    }

    printf("Matrica nakon zamjene redova:\n");
    for (i = 0; i < DIM; i++) {
        for (j = 0; j < DIM; j++) {
            printf("%d ", matrica[i][j]);
        }
        printf("\n");
    }

    return 0;
}
